  auto headers = Http::TestRequestHeaderMapImpl{{":scheme", "http"}, {":authority", "host.com"}};
  config.headerEvaluator().evaluateHeaders(headers, {}, stream_info);
  EXPECT_EQ("test_val", headers.get_("test_key"));
}

